/**
 * Project Zero Review Extension
 *
 * Provides a `/pz-review` command that asks the coding agent to review a completed
 * implementation against the Project Zero contract files generated by ChatGPT.
 *
 * Main purpose:
 * - Contract compliance review: did the implementation satisfy project-zero/*?
 * - Scope discipline review: did the previous build stay inside Layer 1?
 * - Verification review: do build/test/browser-check artifacts support acceptance?
 * - Normal code review side quest: bugs, security, runtime, and maintainability.
 *
 * Install:
 * - Put this file at `~/.pi/agent/extensions/project-zero-review.ts` for global use, or
 * - Put it at `.pi/extensions/project-zero-review.ts` for one project.
 * - Run `/reload` in pi.
 *
 * Usage:
 * - `/pz-review`
 * - `/pz-review --base main`
 * - `/pz-review --no-build`
 * - `/pz-review --extra "focus on localStorage persistence"`
 * - `/pz-review --help`
 *
 * Behavior notes:
 * - Cross-platform: source-tree preflight is computed in-process with `fs.readdir`
 *   (no `find` binary dependency).
 * - Esc-cancellable: preflight shell calls and the file walk honor `ctx.signal`.
 * - Safe while busy: if the agent is mid-turn, the review is queued as a follow-up
 *   instead of throwing.
 * - Tab completion is provided for `--base`, `--no-build`, `--extra`, `--help`, `-h`.
 * - The review session is named "Project Zero Review" (suffixed with the current
 *   git branch when available) so it is easy to find in `/resume`.
 */

import { spawnSync } from "node:child_process";
import { promises as fs, type Dirent } from "node:fs";
import path from "node:path";
import type { ExtensionAPI, ExtensionCommandContext } from "@earendil-works/pi-coding-agent";
import type { AutocompleteItem } from "@earendil-works/pi-tui";

const COMMAND_NAME = "pz-review";
const PROJECT_ZERO_DIR = "project-zero";
const REVIEW_REPORT_PATH = "reports/project-zero-review-report.md";
const MAX_FILE_CHARS = 30_000;
const MAX_TREE_FILES = 500;
const MAX_TREE_DEPTH = 3;

const ARG_OPTIONS = ["--base", "--no-build", "--extra", "--help", "-h"] as const;

const SKIP_DIRS = new Set([
  "node_modules",
  ".git",
  ".next",
  "dist",
  "build",
  ".pi",
  "coverage",
  ".turbo",
  "out",
  "target",
]);

const REQUIRED_PROJECT_ZERO_FILES = [
  "project-zero/00-idea-interview.md",
  "project-zero/01-product-kernel.md",
  "project-zero/02-layer-1-spec.md",
  "project-zero/03-build-verification.md",
  "project-zero/04-build-goal.md",
  "project-zero/05-browser-check-plan.md",
  "project-zero/06-browser-check-goal.md",
  "project-zero/07-fix-goal-template.md",
  "project-zero/project-state.json",
] as const;

const OPTIONAL_EVIDENCE_FILES = [
  "reports/browser-check-report.md",
  "README.md",
  "TODO.md",
  "package.json",
] as const;

type ProjectZeroReviewOptions = {
  baseBranch?: string;
  noBuild?: boolean;
  extraInstruction?: string;
  help?: boolean;
};

type ExistingFileSnapshot = {
  path: string;
  content: string;
  truncated: boolean;
};

type DetectionResult = {
  hasProjectZeroDir: boolean;
  requiredFiles: ExistingFileSnapshot[];
  optionalFiles: ExistingFileSnapshot[];
  missingRequiredFiles: string[];
  packageScripts: Record<string, string>;
  gitStatus?: string;
  sourceTree?: string;
};

type ExecTextOptions = {
  timeout?: number;
  signal?: AbortSignal;
};

function truncateForPrompt(value: string, maxChars = MAX_FILE_CHARS): { value: string; truncated: boolean } {
  if (value.length <= maxChars) {
    return { value, truncated: false };
  }

  const headChars = Math.floor(maxChars * 0.7);
  const tailChars = maxChars - headChars;
  return {
    value: `${value.slice(0, headChars)}\n\n[... truncated ${value.length - maxChars} characters ...]\n\n${value.slice(-tailChars)}`,
    truncated: true,
  };
}

async function pathExists(filePath: string): Promise<boolean> {
  return fs.stat(filePath).then(() => true).catch(() => false);
}

async function readTextFileIfExists(cwd: string, relativePath: string): Promise<ExistingFileSnapshot | null> {
  const absolutePath = path.join(cwd, relativePath);
  const stats = await fs.stat(absolutePath).catch(() => null);
  if (!stats?.isFile()) {
    return null;
  }

  const raw = await fs.readFile(absolutePath, "utf8");
  const truncated = truncateForPrompt(raw);
  return {
    path: relativePath,
    content: truncated.value,
    truncated: truncated.truncated,
  };
}

function parsePackageScripts(packageJsonContent: string | undefined): Record<string, string> {
  if (!packageJsonContent?.trim()) {
    return {};
  }

  try {
    const parsed = JSON.parse(packageJsonContent) as { scripts?: unknown };
    if (!parsed.scripts || typeof parsed.scripts !== "object" || Array.isArray(parsed.scripts)) {
      return {};
    }

    const scripts: Record<string, string> = {};
    for (const [key, value] of Object.entries(parsed.scripts)) {
      if (typeof value === "string") {
        scripts[key] = value;
      }
    }
    return scripts;
  } catch {
    return {};
  }
}

function describeArgOption(flag: string): string {
  switch (flag) {
    case "--base":
      return "compare against a base branch (e.g. main)";
    case "--no-build":
      return "skip running npm run build";
    case "--extra":
      return "additional review instruction";
    case "--help":
    case "-h":
      return "show usage";
    default:
      return "";
  }
}

function inferBranchName(cwd: string): string | undefined {
  try {
    const result = spawnSync("git", ["rev-parse", "--abbrev-ref", "HEAD"], {
      cwd,
      encoding: "utf8",
      timeout: 2_000,
    });
    if (result.status !== 0) return undefined;
    const branch = result.stdout?.trim();
    return branch && branch.length > 0 ? branch : undefined;
  } catch {
    return undefined;
  }
}

/**
 * Walk the workspace tree in-process, returning a deterministic, sorted,
 * depth-limited file listing as a single string suitable for prompt inclusion.
 *
 * Cross-platform: uses `fs.readdir` only, so it works on Windows, macOS, and
 * Linux without relying on a `find` binary on PATH.
 */
async function listSourceTree(cwd: string, signal?: AbortSignal): Promise<string> {
  const lines: string[] = [];
  let truncated = false;
  let aborted = false;

  async function walk(dir: string, depth: number, prefix: string): Promise<void> {
    if (signal?.aborted) {
      aborted = true;
      return;
    }
    if (depth > MAX_TREE_DEPTH) return;
    if (lines.length >= MAX_TREE_FILES) {
      truncated = true;
      return;
    }

    let entries: Dirent[];
    try {
      entries = await fs.readdir(dir, { withFileTypes: true });
    } catch {
      return;
    }

    // Stable order so re-running the review produces the same snapshot.
    entries.sort((a, b) => a.name.localeCompare(b.name));

    for (const entry of entries) {
      if (signal?.aborted) {
        aborted = true;
        return;
      }
      if (lines.length >= MAX_TREE_FILES) {
        truncated = true;
        return;
      }

      const rel = prefix ? `${prefix}/${entry.name}` : entry.name;

      if (entry.isDirectory()) {
        if (SKIP_DIRS.has(entry.name)) continue;
        await walk(path.join(dir, entry.name), depth + 1, rel);
      } else if (entry.isFile()) {
        lines.push(rel);
      }
    }
  }

  await walk(cwd, 0, "");

  if (aborted) {
    return lines.length > 0
      ? `${lines.join("\n")}\n... (aborted before completion)`
      : "(aborted before completion)";
  }
  if (truncated) {
    lines.push(`... (truncated to ${MAX_TREE_FILES} files at depth ${MAX_TREE_DEPTH})`);
  }
  return lines.join("\n");
}

async function execText(
  pi: ExtensionAPI,
  command: string,
  args: string[],
  options: ExecTextOptions = {},
): Promise<string | undefined> {
  const { timeout = 10_000, signal } = options;
  try {
    const result = await pi.exec(command, args, { timeout, signal });
    const chunks = [
      `$ ${[command, ...args].join(" ")}`,
      `exit code: ${result.code}`,
    ];
    if (result.stdout?.trim()) chunks.push(`stdout:\n${result.stdout.trim()}`);
    if (result.stderr?.trim()) chunks.push(`stderr:\n${result.stderr.trim()}`);
    if (result.killed) chunks.push("process was killed by timeout");
    return chunks.join("\n");
  } catch (error) {
    return `$ ${[command, ...args].join(" ")}\nfailed to run: ${error instanceof Error ? error.message : String(error)}`;
  }
}

async function detectProjectZero(pi: ExtensionAPI, ctx: ExtensionCommandContext): Promise<DetectionResult> {
  const cwd = ctx.cwd;
  const signal = ctx.signal;

  const hasProjectZeroDir = await pathExists(path.join(cwd, PROJECT_ZERO_DIR));

  const requiredFiles: ExistingFileSnapshot[] = [];
  const missingRequiredFiles: string[] = [];
  for (const relativePath of REQUIRED_PROJECT_ZERO_FILES) {
    const snapshot = await readTextFileIfExists(cwd, relativePath);
    if (snapshot) {
      requiredFiles.push(snapshot);
    } else {
      missingRequiredFiles.push(relativePath);
    }
  }

  const optionalFiles: ExistingFileSnapshot[] = [];
  for (const relativePath of OPTIONAL_EVIDENCE_FILES) {
    const snapshot = await readTextFileIfExists(cwd, relativePath);
    if (snapshot) {
      optionalFiles.push(snapshot);
    }
  }

  const packageJson = optionalFiles.find((file) => file.path === "package.json")?.content;
  const packageScripts = parsePackageScripts(packageJson);

  const gitStatus = await execText(pi, "git", ["status", "--porcelain"], { timeout: 5_000, signal });

  // Cross-platform source tree. In-process, deterministic, signal-aware.
  // Replaces the previous `pi.exec("find", ...)` which required GNU `find` on PATH
  // and silently failed on Windows.
  const sourceTree = await listSourceTree(cwd, signal);

  return {
    hasProjectZeroDir,
    requiredFiles,
    optionalFiles,
    missingRequiredFiles,
    packageScripts,
    gitStatus,
    sourceTree,
  };
}

function tokenizeArgs(value: string): string[] {
  const tokens: string[] = [];
  let current = "";
  let quote: '"' | "'" | null = null;

  for (let i = 0; i < value.length; i++) {
    const char = value[i];

    if (quote) {
      if (char === "\\" && i + 1 < value.length) {
        current += value[i + 1];
        i += 1;
        continue;
      }
      if (char === quote) {
        quote = null;
        continue;
      }
      current += char;
      continue;
    }

    if (char === '"' || char === "'") {
      quote = char;
      continue;
    }

    if (/\s/.test(char)) {
      if (current.length > 0) {
        tokens.push(current);
        current = "";
      }
      continue;
    }

    current += char;
  }

  if (current.length > 0) {
    tokens.push(current);
  }

  return tokens;
}

function parseArgs(args: string | undefined): { options: ProjectZeroReviewOptions; error?: string } {
  const options: ProjectZeroReviewOptions = {};
  const tokens = tokenizeArgs(args?.trim() ?? "");

  for (let i = 0; i < tokens.length; i++) {
    const token = tokens[i];

    if (token === "--help" || token === "-h") {
      options.help = true;
      continue;
    }

    if (token === "--no-build") {
      options.noBuild = true;
      continue;
    }

    if (token === "--base") {
      const value = tokens[i + 1];
      if (!value) {
        return { options, error: "Missing value for --base" };
      }
      options.baseBranch = value;
      i += 1;
      continue;
    }

    if (token.startsWith("--base=")) {
      const value = token.slice("--base=".length).trim();
      if (!value) {
        return { options, error: "Missing value for --base" };
      }
      options.baseBranch = value;
      continue;
    }

    if (token === "--extra") {
      const value = tokens[i + 1];
      if (!value) {
        return { options, error: "Missing value for --extra" };
      }
      options.extraInstruction = value;
      i += 1;
      continue;
    }

    if (token.startsWith("--extra=")) {
      const value = token.slice("--extra=".length).trim();
      if (!value) {
        return { options, error: "Missing value for --extra" };
      }
      options.extraInstruction = value;
      continue;
    }

    return { options, error: `Unknown option: ${token}` };
  }

  return { options };
}

function formatFileSnapshot(file: ExistingFileSnapshot): string {
  const truncationNote = file.truncated ? "\n\n> Note: this file was truncated in the prompt snapshot. Inspect the real file before making final findings." : "";
  return `## ${file.path}\n\n\`\`\`\n${file.content}\n\`\`\`${truncationNote}`;
}

function formatScripts(scripts: Record<string, string>): string {
  const entries = Object.entries(scripts);
  if (entries.length === 0) {
    return "No package scripts detected, or package.json is missing/invalid.";
  }

  return entries.map(([name, value]) => `- ${name}: ${value}`).join("\n");
}

function buildUsageText(): string {
  return `# Project Zero Review Extension\n\nUsage:\n\n\`\`\`text\n/pz-review\n/pz-review --base main\n/pz-review --no-build\n/pz-review --extra "focus on localStorage persistence"\n/pz-review --help\n\`\`\`\n\nWhat it does:\n- Reviews the completed implementation against the Project Zero contract.\n- Checks Layer 1 scope discipline.\n- Asks the agent to run verification commands and inspect code.\n- Produces \`${REVIEW_REPORT_PATH}\`.\n\nIt does not auto-fix. Use the generated report as input to a separate Fix Goal.`;
}

function buildReviewPrompt(detection: DetectionResult, options: ProjectZeroReviewOptions): string {
  const buildInstruction = options.noBuild
    ? "Do not run `npm run build` because the user passed `--no-build`. Mark build verification as not run by user request."
    : detection.packageScripts.build
      ? "Run `npm run build` and include the exact pass/fail result."
      : "If there is no build script, do not invent one. Mark build verification as not configured and inspect package.json.";

  const testInstruction = detection.packageScripts.test
    ? "Run `npm test` unless the script is clearly interactive or destructive. Include the exact result."
    : "Do not run tests unless a test script exists. Mark tests as not configured if missing.";

  const lintInstruction = detection.packageScripts.lint
    ? "Run `npm run lint` unless the script is clearly interactive or destructive. Include the exact result."
    : "Do not run lint unless a lint script exists. Mark lint as not configured if missing.";

  const baseBranchInstruction = options.baseBranch
    ? `Also review the implementation diff against base branch \`${options.baseBranch}\`. Find the merge base if possible, run the relevant git diff, and use the diff only as supporting evidence. The Project Zero contract remains the source of truth.`
    : "This is a snapshot contract review of the current workspace. Do not require a pull request or base branch to make findings.";

  const missingRequired = detection.missingRequiredFiles.length > 0
    ? detection.missingRequiredFiles.map((file) => `- ${file}`).join("\n")
    : "- None";

  const requiredSnapshots = detection.requiredFiles.length > 0
    ? detection.requiredFiles.map(formatFileSnapshot).join("\n\n---\n\n")
    : "No required Project Zero files were readable in the extension preflight snapshot.";

  const optionalSnapshots = detection.optionalFiles.length > 0
    ? detection.optionalFiles.map(formatFileSnapshot).join("\n\n---\n\n")
    : "No optional evidence files were found in the extension preflight snapshot.";

  const extra = options.extraInstruction?.trim()
    ? `\n\n## Additional user-provided review instruction\n\n${options.extraInstruction.trim()}`
    : "";

  return `# Project Zero Contract Review\n\nYou are reviewing a completed coding-agent implementation against a Project Zero contract.\n\nMain objective:\nDetermine whether the implementation faithfully satisfies the Project Zero contract files and whether the previous coding-agent session completed the promised Layer 1 app.\n\nPriority order:\n1. Contract compliance\n2. Layer 1 scope discipline\n3. Build/test/browser-check evidence\n4. Code correctness, bugs, security, maintainability\n\n## Operating rules\n\n- Do not add features.\n- Do not fix code.\n- Do not rewrite the app.\n- Review only, then create or update \`${REVIEW_REPORT_PATH}\`.\n- Treat \`reports/browser-check-report.md\` as evidence, not truth. Verify whether it contains concrete evidence.\n- Use the Project Zero files as the contract source of truth.\n- If contract files disagree with one another, flag the ambiguity as a human-decision finding.\n- Findings must be discrete, actionable, and evidence-based.\n- Use [P0], [P1], [P2], [P3].\n- Use \`correct\` only when the implementation satisfies the contract and no blocking findings remain.\n- Use \`needs attention\` if any P0/P1/P2 finding blocks acceptance.\n\n## Required Project Zero file order\n\nReview these files in this order:\n\n${REQUIRED_PROJECT_ZERO_FILES.map((file) => `- ${file}`).join("\n")}\n\n## Missing required Project Zero files from extension preflight\n\n${missingRequired}\n\n## Package scripts detected\n\n${formatScripts(detection.packageScripts)}\n\n## Verification instructions\n\n- Run \`git status --porcelain\` and include the result.\n- ${baseBranchInstruction}\n- Inspect package.json, README.md, TODO.md, and the relevant source files.\n- ${buildInstruction}\n- ${testInstruction}\n- ${lintInstruction}\n- Inspect \`reports/browser-check-report.md\` if present.\n- Confirm whether \`reports/browser-check-report.md\` includes: local URL, commands run, passed checks, failed checks, bugs found, fixes made if any, remaining issues, and concrete browser evidence.\n- If a required command is unavailable or blocked, report the exact error/output and continue with file inspection.\n\n## What to check\n\n### Contract compliance\n\nCheck whether:\n\n- Every required Layer 1 feature from \`02-layer-1-spec.md\` is implemented.\n- The core loop from \`01-product-kernel.md\` works in the code.\n- The implementation matches \`03-build-verification.md\`.\n- The Browser Check Plan and Browser Check Goal are plausible and reflected in the report, if present.\n- \`project-state.json\` agrees with the actual app.\n- README.md and TODO.md exist if required by the contract.\n- The app preserves the intended small/local-first product-loop simulator scope.\n\n### Scope discipline\n\nFlag any forbidden Layer 1 additions, especially:\n\n- backend\n- database\n- auth\n- API\n- deployment plumbing\n- payments\n- teams/admin panels\n- AI features\n- analytics/notifications\n- external UI frameworks, unless explicitly allowed by the Project Zero files\n\n### Code review side quest\n\nAlso look for:\n\n- runtime bugs\n- broken state transitions\n- broken localStorage persistence\n- missing seed data\n- unsafe handling of user-controlled values\n- silent fallback behavior that hides failure\n- tests/build scripts that do not verify what they claim\n- dependencies that contradict the Layer 1 stack\n\n## Output format\n\nCreate or update \`${REVIEW_REPORT_PATH}\` with exactly this structure:\n\n\`\`\`md\n# Project Zero Review Report\n\n## Review Scope\n- Project:\n- Date:\n- Contract files inspected:\n- Implementation areas inspected:\n- Commands run:\n- Browser report inspected:\n\n## Contract Verdict\ncorrect | needs attention\n\n## Implementation Verdict\ncorrect | needs attention\n\n## Contract Findings\n### [P0/P1/P2/P3] Finding title\n- Contract source:\n- Implementation evidence:\n- Why it matters:\n- Required fix:\n\nIf none, write: - None.\n\n## Code Findings\n### [P0/P1/P2/P3] Finding title\n- File:\n- Evidence:\n- Why it matters:\n- Required fix:\n\nIf none, write: - None.\n\n## Scope Creep Findings\n### [P0/P1/P2/P3] Finding title\n- Forbidden by:\n- Found in:\n- Why it matters:\n- Required fix:\n\nIf none, write: - None.\n\n## Verification Results\n- git status:\n- build:\n- tests:\n- lint:\n- browser report:\n\n## Human Reviewer Callouts\nInclude only applicable callouts. If none apply, write: - (none).\n\n- New dependency:\n- Changed dependency or lockfile:\n- Backend/API/auth/database introduced:\n- Destructive behavior:\n- Ambiguous product decision:\n- Browser evidence insufficient:\n\n## Final Recommendation\nready for acceptance | needs fix goal | needs human decision\n\n## Fix Goal Input\nIf the recommendation is \`needs fix goal\`, provide a compact checklist of verified issues to feed into a Fix Goal.\n\`\`\`\n\nAfter writing the report, summarize the verdict in chat and include the path \`${REVIEW_REPORT_PATH}\`.\n${extra}\n\n---\n\n# Extension preflight context\n\n## Has project-zero directory\n\n${detection.hasProjectZeroDir ? "yes" : "no"}\n\n## git status preflight\n\n\`\`\`text\n${detection.gitStatus ?? "not available"}\n\`\`\`\n\n## workspace file tree preflight\n\n\`\`\`text\n${detection.sourceTree ?? "not available"}\n\`\`\`\n\n---\n\n# Project Zero contract file snapshots\n\n${requiredSnapshots}\n\n---\n\n# Optional evidence file snapshots\n\n${optionalSnapshots}\n`;
}

async function runProjectZeroReview(pi: ExtensionAPI, ctx: ExtensionCommandContext, args: string | undefined): Promise<void> {
  const parsed = parseArgs(args);
  if (parsed.error) {
    ctx.ui.notify(parsed.error, "error");
    return;
  }

  if (parsed.options.help) {
    if (ctx.hasUI) {
      ctx.ui.setEditorText(buildUsageText());
      ctx.ui.notify("Project Zero review usage inserted into editor.", "info");
    } else {
      pi.sendUserMessage(buildUsageText());
    }
    return;
  }

  // Name the review session early so it is easy to find in /resume.
  // Never throw — the branch-name probe is best-effort.
  if (ctx.hasUI) {
    const branchName = inferBranchName(ctx.cwd);
    pi.setSessionName(branchName ? `Project Zero Review (${branchName})` : "Project Zero Review");
  }

  const detection = await detectProjectZero(pi, ctx);
  if (!detection.hasProjectZeroDir) {
    ctx.ui.notify("No project-zero/ directory found in the current working directory.", "error");
    return;
  }

  if (detection.missingRequiredFiles.length > 0) {
    ctx.ui.notify(
      `Project Zero contract is missing ${detection.missingRequiredFiles.length} required file(s); review will flag this.`,
      "warning",
    );
  }

  const prompt = buildReviewPrompt(detection, parsed.options);
  ctx.ui.notify("Starting Project Zero contract review.", "info");

  // If the agent is mid-turn, sendUserMessage with no deliverAs would throw
  // "Agent is already processing...". Queue as a follow-up so /pz-review is
  // safely invokable any time. When idle, sendUserMessage triggers a new turn
  // immediately per the documented behavior.
  if (!ctx.isIdle()) {
    ctx.ui.notify("Agent is busy — /pz-review will run as a follow-up.", "info");
    pi.sendUserMessage(prompt, { deliverAs: "followUp" });
    return;
  }
  pi.sendUserMessage(prompt);
}

export default function projectZeroReviewExtension(pi: ExtensionAPI) {
  pi.registerCommand(COMMAND_NAME, {
    description: "Review implementation against Project Zero contract files",
    getArgumentCompletions: (prefix: string): AutocompleteItem[] | null => {
      // Only suggest flag names; pi's built-in path/text completion takes over
      // for the value (e.g. branch name after `--base `).
      const items: AutocompleteItem[] = ARG_OPTIONS
        .filter((opt) => opt.startsWith(prefix))
        .map((value) => ({ value, label: value, description: describeArgOption(value) }));
      return items.length > 0 ? items : null;
    },
    handler: async (args, ctx) => {
      await runProjectZeroReview(pi, ctx, args);
    },
  });
}
